// =====================================================
// CONFIGURACIÓN DEL RANGO DE FECHAS Y REPOSITORIO
// Calcula fechaInicio, fechaFin y define colaboradores
// =====================================================


// =====================================================
// FECHA ACTUAL AJUSTADA A CHILE (UTC-3)
// =====================================================
const hoy = new Date();
hoy.setMinutes(hoy.getMinutes() + hoy.getTimezoneOffset() + 180);


// =====================================================
// FECHA FIN → ÚLTIMO DÍA HÁBIL
// =====================================================
const fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);

while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}


// =====================================================
// FECHA INICIO → ÚLTIMO VIERNES MES ANTERIOR
// =====================================================
const fechaInicio = new Date(
  fechaFin.getFullYear(),
  fechaFin.getMonth(),
  0
);

while (fechaInicio.getDay() !== 5) {
  fechaInicio.setDate(fechaInicio.getDate() - 1);
}


// =====================================================
// FORMATEO DE FECHAS PARA TEXTO DEL REPORTE
// =====================================================
const MESES = [
  'enero','febrero','marzo','abril','mayo','junio',
  'julio','agosto','septiembre','octubre','noviembre','diciembre'
];

const inicioTexto =
  String(fechaInicio.getDate()).padStart(2,'0') +
  ' de ' + MESES[fechaInicio.getMonth()];

const finTexto =
  String(fechaFin.getDate()).padStart(2,'0') +
  ' de ' + MESES[fechaFin.getMonth()];

const periodoTexto = `${inicioTexto} – ${finTexto}`;
const mesCurso = MESES[fechaFin.getMonth()].toUpperCase().slice(0,3);


// ===============================
// REPOSITORIO DE PERSONAS
// ===============================
const personas = [
