  { personId:356965,nombre:'Margarita',apellidoP:'Olmedo',apellidoM:'',area:'Dl Innova' },
  { personId:408021,nombre:'Carlos',apellidoP:'Martínez',apellidoM:'',area:'Dl Innova' },
