  { personId:357120,nombre:'Rodrigo',apellidoP:'Ruiz',apellidoM:'',area:'Marketing' },
  { personId:428509,nombre:'Beatriz',apellidoP:'Quilodrán',apellidoM:'',area:'Dl Personas' }
];


// ===============================
// OUTPUT
// ===============================
return {
  fechaInicio: fechaInicio.toISOString().slice(0,10),
  fechaFin: fechaFin.toISOString().slice(0,10),
  periodoTexto,
  mesCurso,
  personas
};

// =====================================================
// CÁLCULO DE DÍAS LABORABLES Y HORAS ESPERADAS
// =====================================================

const repo = $input.first().json;
const inicio = new Date(repo.fechaInicio);
const fin = new Date(repo.fechaFin);

let diasLaborables = 0;
let horasTotales = 0;

for (let d = new Date(inicio); d <= fin; d.setDate(d.getDate() + 1)) {

  const dia = d.getDay();

  if (dia >= 1 && dia <= 4) {
    diasLaborables++;
    horasTotales += 8;
  } else if (dia === 5) {
    diasLaborables++;
    horasTotales += 6.5;
  }
}

// ===============================
// OUTPUT
// ===============================
return {
  json: {
    diasLaborables,
    horasTotales: +horasTotales.toFixed(1),
    personas: repo.personas,
    mesCurso: repo.mesCurso
  }
};

// =====================================================
// EXPANSIÓN DEL REPOSITORIO POR COLABORADOR
// Permite ejecución individual en API
// =====================================================

const { personas, diasLaborables, horasTotales, mesCurso } = $input.first().json;

return personas.map(p => ({
  json: {
    personId: p.personId,
    nombre: `${p.nombre} ${p.apellidoP} ${p.apellidoM || ''}`.trim(),
    area: p.area,
    diasLaborables,
    horasEsperadas: horasTotales,
    mesCurso
  }
}));

// ===============================
// OBTENER PERSONAS PREPARADAS
// ===============================
const personasArray = $('Preparar datos personas').all().map(p => p.json);

// Mapa por personId
const personas = Object.fromEntries(
  personasArray.map(p => [p.personId, p])
);

// Días laborales del período
const diasLaborables = $('Calculo de horas').first().json.diasLaborables;

const resultados = [];


// ===============================
// MAPA DE HORAS POR PERSONA
// ===============================
const horasPorPersona = {};

// Consolidar respuesta del HTTP
for (const item of $input.all()) {

  const registros = item.json.time || [];

  // Si no hay registros, se ignora
  if (!registros.length) continue;

  const personId = Number(registros[0].personid);

  // Sumar todas las horas retornadas
  const totalHoras = registros.reduce(
    (acc, r) => acc + Number(r.time || 0),
    0
  );

  // Acumular por persona
  horasPorPersona[personId] =
    (horasPorPersona[personId] || 0) + totalHoras;
}


// ===============================
// GENERAR RESULTADOS
// ===============================
for (const persona of personasArray) {

  const horasEsperadas = persona.horasEsperadas;

  // Si no aparece en la API, se considera 0
  const horasIngresadas =
    +(horasPorPersona[persona.personId] || 0).toFixed(1);

  const diferencia =
    +(horasEsperadas - horasIngresadas).toFixed(1);

  // Cálculo porcentaje cumplimiento
  const porcentaje = horasEsperadas > 0
    ? Math.round((horasIngresadas / horasEsperadas) * 100)
    : 0;

  // Clasificación automática por nivel
  let estado =
    porcentaje > 100 ? '✅ ¿Al día?' :
    porcentaje === 100 ? '✅ Al día' :
    porcentaje >= 80 ? '⚠️ Pendiente' :
    '❌ Atrasado';

  // Mandar los resultados para consumir en HTML
  resultados.push({
    Area: persona.area,
    Nombre: persona.nombre,
    horasEsperadas: +horasEsperadas.toFixed(1),
    horasIngresadas,
    diferencia,
    semanasPendientes:
      diferencia > 0 ? +((diferencia / 40).toFixed(1)) : 0,
    porcentaje,
    estado,
    mesCurso: persona.mesCurso,
    diasLaborables
  });
}


// ===============================
// ORDENAR
// ===============================
return resultados.sort((a,b) => a.diferencia - b.diferencia);

// ===============================
// FUENTES DE DATOS
// ===============================
const datos = $input.all();
const repo = $('Repositorio').first().json;


// ===============================
// METADATA DEL REPORTE
// ===============================
const periodoInicio = repo.fechaInicio;
const periodoFin = repo.fechaFin;

// Valores globales (se repiten en todos los registros)
const diasLaborables =
  datos.length ? datos[0].json.diasLaborables : 0;

const horasEsperadasPeriodo =
  datos.length && !isNaN(datos[0].json.horasEsperadas)
    ? datos[0].json.horasEsperadas
    : 0;

const totalColaboradores = datos.length;


// ===============================
// RESUMEN ESTADÍSTICO
// ===============================
const alDia = datos.filter(i =>
  i.json.estado === '✅ Al día' ||
  i.json.estado === '✅ ¿Al día?'
).length;

const pendientes = datos.filter(i =>
  i.json.estado === '⚠️ Pendiente'
).length;

const atrasados = datos.filter(i =>
  i.json.estado === '❌ Atrasado'
).length;


// ===============================
// CONSTRUCCIÓN FILAS TABLA
// ===============================
let filas = '';

for (const { json: d } of datos) {

  // Color según estado
  const colorFila =
    d.estado === '✅ Al día' || d.estado === '✅ ¿Al día?' ? '#e8f5e9' :
    d.estado === '⚠️ Pendiente' ? '#fff8e1' :
    '#fdecea';

  filas += `
    <tr style="background:${colorFila};">
      <td><strong>${d.Area}</strong></td>
      <td><strong>${d.Nombre}</strong></td>
      <td><strong>${d.horasEsperadas}</strong></td>
      <td><strong>${d.horasIngresadas}</strong></td>
      <td><strong>${Math.abs(d.diferencia)}</strong></td>
      <td><strong>${d.porcentaje}%</strong></td>
      <td><strong>${d.estado}</strong></td>
      <td><strong>${d.semanasPendientes}</strong></td>
    </tr>`;
}

// ===============================
// HTML FINAL
// ===============================
const htmlCompleto = `
<!DOCTYPE html>
<html>
<head>
