        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${d.json.porcentaje}%
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">
        <strong>${d.json.estado}</strong>
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${d.json.semanasPendientes}
    </td>

